#!/usr/bin/perl
use strict;
use warnings;
use CGI;
use URI;
use URI::Escape;

my $cgi = CGI->new;

my $next = $cgi->param('next') || '';

my $default_url = '/dashboard';

my $redirect_url = validate_and_sanitize_redirect($next, $default_url);

print $cgi->header(
    -type => 'text/html',
    -status => '302 Found',
    -location => $redirect_url
);

sub validate_and_sanitize_redirect {
    my ($url, $default) = @_;
    
    return $default unless defined $url && $url ne '';
    
    $url =~ s/^\s+|\s+$//g;
    
    return $default if $url =~ /[\r\n]/;
    
    return $default if $url =~ m{^(?:javascript|data|vbscript|file):}i;
    
    my $uri;
    eval {
        $uri = URI->new($url);
    };
    return $default if $@;
    
    if ($uri->scheme) {
        my $scheme = lc($uri->scheme);
        return $default unless $scheme eq 'http' || $scheme eq 'https';
        
        my $host = $uri->host;
        return $default unless $host;
        
        my @allowed_domains = get_allowed_domains();
        my $allowed = 0;
        foreach my $domain (@allowed_domains) {
            if ($host eq $domain || $host =~ /\.\Q$domain\E$/) {
                $allowed = 1;
                last;
            }
        }
        return $default unless $allowed;
    } else {
        return $default if $url =~ m{^//};
        
        return $default unless $url =~ m{^/[^/]};
        
        my $path = $uri->path;
        return $default if $path =~ /\.\./;
    }
    
    return $url;
}

sub get_allowed_domains {
    my $server_name = $ENV{SERVER_NAME} || 'localhost';
    
    return (
        $server_name,
        'www.' . $server_name,
    );
